use dioxus::prelude::*;#[allow(unused_imports)]use dioxus_router::prelude::*;use crate::ui::{layout::Layout,pages::{Dashboard,Login,NotFound,Profile},router::Route,state::AppStateProvider,};#[component]pub fn App()->Element{rsx!{AppStateProvider{Router::<Route>{}}}}#[component]fn RootLayout()->Element{rsx!{AppStateProvider{div{class:"min-h-screen bg-gray-50",Outlet::<Route>{}}}}}#[component]fn AuthGuard(children:Element)->Element{let app_state=use_context::<crate::ui::state::AppStateContext>();let is_authenticated=app_state.current_user.is_some();if is_authenticated{rsx!{{children}}}else{rsx!{div{class:"min-h-screen flex items-center justify-center bg-gray-50",Login{}}}}}#[component]fn ProtectedRoute(children:Element)->Element{rsx!{AuthGuard{Layout{{children}}}}}#[derive(Clone,Routable,Debug,PartialEq)]pub enum AppRoute{#[route("/")]#[redirect("/dashboard",||AppRoute::DashboardPage{})]HomePage{},#[route("/login")]LoginPage{},#[route("/dashboard")]DashboardPage{},#[route("/profile")]ProfilePage{},#[route("/:..route")]NotFoundPage{route:Vec<String>},}#[component]fn HomePage()->Element{rsx!{ProtectedRoute{Dashboard{}}}}#[component]fn LoginPage()->Element{rsx!{div{class:"min-h-screen flex items-center justify-center bg-gray-50",Login{}}}}#[component]fn DashboardPage()->Element{rsx!{ProtectedRoute{Dashboard{}}}}#[component]fn ProfilePage()->Element{rsx!{ProtectedRoute{Profile{}}}}#[component]fn NotFoundPage(route:Vec<String>)->Element{rsx!{div{class:"min-h-screen flex items-center justify-center bg-gray-50",NotFound{path:route.join("/")}}}}#[cfg(test)]mod tests{use super::*;use dioxus::prelude::*;#[test]fn app_component_renders(){let mut vdom=VirtualDom::new(App);let _=vdom.rebuild_in_place();}}
